// Simulating React useState behavior
function useState<T>(initial: T): [T, (newVal: T | ((prev: T) => T)) => T] {
  let state = initial;
  const setter = (newVal: T | ((prev: T) => T)): T => {
    if (typeof newVal === 'function') {
      state = (newVal as (prev: T) => T)(state);
    } else {
      state = newVal;
    }
    return state;
  };
  return [state, setter];
}

