// Create a FormManager class with a generic type parameter T
// Constructor takes initial state of type T
// get(): T - returns current state
// set(updates: Partial<T>): void - merges partial updates
// reset(): void - resets to initial state

// Test with: { username: '', email: '', age: 0 }
// Set username to 'Alice', email to 'alice@test.com'
// Print the state
// Set age to 30
// Print the state
// Reset and print

// Your code here

exercises.solution:
class FormManager<T extends Record<string, any>> {
  private state: T;
  private initialState: T;

  constructor(initial: T) {
    this.initialState = { ...initial };
    this.state = { ...initial };
  }

  get(): T {
    return { ...this.state };
  }

  set(updates: Partial<T>): void {
    this.state = { ...this.state, ...updates };
  }

  reset(): void {
    this.state = { ...this.initialState };
  }
}

const form = new FormManager({ username: '', email: '', age: 0 });
form.set({ username: 'Alice', email: 'alice@test.com' });
console.log(JSON.stringify(form.get()));
form.set({ age: 30 });
console.log(JSON.stringify(form.get()));
form.reset();
console.log(JSON.stringify(form.get()));

