// Reusable context factory pattern
function createSafeContext<T>(name: string): {
  provider: (value: T) => void;
  use: () => T;
} {
  let value: T | undefined = undefined;

  return {
    provider(val: T): void {
      value = val;
    },
    use(): T {
      if (value === undefined) {
        throw new Error(`${name} context not provided`);
      }
      return value;
    }
  };
}

// Create typed contexts
