// Create a PreviousValueTracker<T> class:
// Constructor takes initial value of type T
// update(newValue: T): void - sets current to newValue, stores old current as previous
// getCurrent(): T - returns current value
// getPrevious(): T | null - returns previous value (null if never updated)

// Test with numbers:
// Start with 1, update to 5, update to 10
// Print current and previous at each step

// Your code here

exercises.solution:
class PreviousValueTracker<T> {
  private current: T;
  private previous: T | null;

  constructor(initial: T) {
    this.current = initial;
    this.previous = null;
  }

  update(newValue: T): void {
    this.previous = this.current;
    this.current = newValue;
  }

  getCurrent(): T {
    return this.current;
  }

  getPrevious(): T | null {
    return this.previous;
  }
}

const tracker = new PreviousValueTracker<number>(1);
console.log(`Current: ${tracker.getCurrent()}, Previous: ${tracker.getPrevious()}`);
tracker.update(5);
console.log(`Current: ${tracker.getCurrent()}, Previous: ${tracker.getPrevious()}`);
tracker.update(10);
console.log(`Current: ${tracker.getCurrent()}, Previous: ${tracker.getPrevious()}`);

