// Create a ContextStore class:
// register<T>(name: string, value: T): void - stores a named context value
// get<T>(name: string): T - returns the value (throw if not found)
// list(): string[] - returns all registered context names

// Register:
// 'theme' with { mode: 'dark', primary: '#3b82f6' }
// 'auth' with { user: 'Alice', token: 'abc123' }
// 'locale' with { lang: 'en', region: 'US' }

// Print list of contexts
// Print theme mode
// Print auth user
// Print locale info

// Your code here

exercises.solution:
class ContextStore {
  private store = new Map<string, any>();

  register<T>(name: string, value: T): void {
    this.store.set(name, value);
  }

  get<T>(name: string): T {
    if (!this.store.has(name)) {
      throw new Error(`Context '${name}' not found`);
    }
    return this.store.get(name) as T;
  }

  list(): string[] {
    return Array.from(this.store.keys());
  }
}

const store = new ContextStore();
store.register('theme', { mode: 'dark', primary: '#3b82f6' });
store.register('auth', { user: 'Alice', token: 'abc123' });
store.register('locale', { lang: 'en', region: 'US' });

console.log(store.list().join(', '));
console.log(store.get<{ mode: string; primary: string }>('theme').mode);
console.log(store.get<{ user: string; token: string }>('auth').user);
const locale = store.get<{ lang: string; region: string }>('locale');
console.log(`${locale.lang}-${locale.region}`);

