function useList<T>(initialItems: T[]): {
  items: () => T[];
  add: (item: T) => void;
  remove: (index: number) => void;
  clear: () => void;
  size: () => number;
} {
  let list = [...initialItems];

  return {
    items: () => [...list],
    add(item: T): void {
      list.push(item);
    },
    remove(index: number): void {
      list.splice(index, 1);
    },
    clear(): void {
      list = [];
    },
    size(): number {
      return list.length;
    }
  };
}

