// Define Action type as a discriminated union:
// { type: 'increment' }
// { type: 'decrement' }
// { type: 'reset', payload: number }

// Define State as { count: number }

// Create useReducer<S, A>(reducer: (state: S, action: A) => S, initial: S)
// Returns: { state: S, dispatch: (action: A) => void }

// Implement a counter reducer
// Dispatch: increment, increment, decrement, reset to 0
// Print state after each dispatch

// Your code here

exercises.solution:
type Action =
  | { type: 'increment' }
  | { type: 'decrement' }
  | { type: 'reset'; payload: number };

interface State {
  count: number;
}

function useReducer<S, A>(reducer: (state: S, action: A) => S, initial: S): {
  getState: () => S;
  dispatch: (action: A) => void;
} {
  let state = initial;
  return {
    getState: () => state,
    dispatch(action: A): void {
      state = reducer(state, action);
    }
  };
}

function counterReducer(state: State, action: Action): State {
  switch (action.type) {
    case 'increment':
      return { count: state.count + 1 };
    case 'decrement':
      return { count: state.count - 1 };
    case 'reset':
      return { count: action.payload };
  }
}

const { getState, dispatch } = useReducer<State, Action>(counterReducer, { count: 10 });

dispatch({ type: 'increment' });
console.log(`Count: ${getState().count}`);
dispatch({ type: 'increment' });
console.log(`Count: ${getState().count}`);
dispatch({ type: 'decrement' });
console.log(`Count: ${getState().count}`);
dispatch({ type: 'reset', payload: 0 });
console.log(`Count: ${getState().count}`);

