// Create Dropdown<T extends Labelable>(items: T[], selectedId: string): string
// Returns formatted string showing all options with [x] for selected and [ ] for others

// Test with:
// items = [
//   { id: '1', label: 'React', stars: 200000 },
//   { id: '2', label: 'Vue', stars: 190000 },
//   { id: '3', label: 'Angular', stars: 80000 }
// ]
// selectedId = '2'

// Your code here

exercises.solution:
interface Labelable {
  id: string;
  label: string;
}

function Dropdown<T extends Labelable>(items: T[], selectedId: string): string {
  return items.map(item => {
    const marker = item.id === selectedId ? '[x]' : '[ ]';
    return `${marker} ${item.label}`;
  }).join('\n');
}

interface Framework extends Labelable {
  stars: number;
}

const frameworks: Framework[] = [
  { id: '1', label: 'React', stars: 200000 },
  { id: '2', label: 'Vue', stars: 190000 },
  { id: '3', label: 'Angular', stars: 80000 }
];

console.log(Dropdown(frameworks, '2'));

