// Create a DataGrid<T extends Record<string, any>> function:
// Parameters: data: T[], columns: (keyof T)[], sortBy: keyof T, order: 'asc' | 'desc'
// Sort the data by the sortBy column
// Render as: "col1 | col2 | col3" header, then each row

// Test with employee data sorted by age descending:
// [{ name: 'Alice', age: 30, dept: 'Eng' }, { name: 'Charlie', age: 35, dept: 'Eng' }, { name: 'Bob', age: 25, dept: 'Design' }]
// columns: ['name', 'age', 'dept'], sortBy: 'age', order: 'desc'

// Your code here

exercises.solution:
function DataGrid<T extends Record<string, any>>(
  data: T[],
  columns: (keyof T)[],
  sortBy: keyof T,
  order: 'asc' | 'desc'
): string {
  const sorted = [...data].sort((a, b) => {
    const aVal = a[sortBy];
    const bVal = b[sortBy];
    const cmp = aVal < bVal ? -1 : aVal > bVal ? 1 : 0;
    return order === 'asc' ? cmp : -cmp;
  });

  const header = columns.map(c => String(c)).join(' | ');
  const rows = sorted.map(row =>
    columns.map(col => String(row[col])).join(' | ')
  );

  return [header, ...rows].join('\n');
}

const employees = [
  { name: 'Alice', age: 30, dept: 'Eng' },
  { name: 'Charlie', age: 35, dept: 'Eng' },
  { name: 'Bob', age: 25, dept: 'Design' }
];

console.log(DataGrid(employees, ['name', 'age', 'dept'], 'age', 'desc'));
